/**
 * stealth.min.js — Browser fingerprint evasion
 * 
 * 参考: MediaCrawler libs/stealth.min.js
 * 来自: puppeteer-extra-plugin-stealth
 * 
 * 功能: 隐藏 Playwright/Puppeteer 自动化特征
 * - 移除 navigator.webdriver 标志
 * - 伪造 Chrome 运行时属性
 * - 覆盖权限查询
 * - 修复 WebGL 指纹
 */

// Minimal stealth evasion for Playwright/Puppeteer
(() => {
  // Remove webdriver detection
  Object.defineProperty(navigator, 'webdriver', {
    get: () => false,
  });

  // Fake chrome runtime
  window.chrome = {
    runtime: {},
    loadTimes: function() {},
    csi: function() {},
    app: {},
  };

  // Override permissions
  const originalQuery = window.navigator.permissions.query;
  window.navigator.permissions.query = (parameters) => (
    parameters.name === 'notifications' ?
      Promise.resolve({ state: Notification.permission }) :
      originalQuery(parameters)
  );

  // Fix plugins length (headless Chrome often has 0)
  Object.defineProperty(navigator, 'plugins', {
    get: () => [1, 2, 3, 4, 5],
  });

  // Fix languages
  Object.defineProperty(navigator, 'languages', {
    get: () => ['zh-CN', 'zh', 'en'],
  });

  // Override iframe contentWindow detection
  const originalAttachShadow = Element.prototype.attachShadow;
  Element.prototype.attachShadow = function(init) {
    if (init && init.mode) {
      init.mode = 'open';
    }
    return originalAttachShadow.call(this, init);
  };
})();
